2900	fn rbtdrc_lode_lifecycle(dir: &Path) -> rbtdre_Verdict {
2901	    rbtdrc_with_ctx(|ctx| {
2902	        let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
2903	        if !ctx.project_root().join(vessel_dir).is_dir() {
2904	            return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
2905	        }
2906	
2907	        // Step 1: ensconce the busybox base into a fresh Lode.
2908	        let _ = std::fs::write(dir.join("01-ensconce.txt"), "ensconcing busybox base");
2909	        let ensconce = match rbtdri_invoke_global(ctx, RBTDGC_ENSCONCE_BOLE, &[vessel_dir], &[]) {
2910	            Ok(r) if r.exit_code == 0 => r,
2911	            Ok(r) => return rbtdre_Verdict::Fail(format!("ensconce failed (exit {})\n{}", r.exit_code, r.stderr)),
2912	            Err(e) => return rbtdre_Verdict::Fail(format!("ensconce invocation: {}", e)),
2913	        };
2914	        let _ = std::fs::write(dir.join("01-ensconce-stdout.txt"), &ensconce.stdout);
2915	
2916	        // The capture-file root is the Lode touchmark.
2917	        let touchmarks = match rbtdri_read_burv_facts_multi(&ensconce, RBTDRC_FACT_EXT_LODE) {
2918	            Ok(v) => v,
2919	            Err(e) => return rbtdre_Verdict::Fail(format!("read capture-file: {}", e)),
2920	        };
2921	        if touchmarks.len() != 1 {
2922	            return rbtdre_Verdict::Fail(format!("expected exactly 1 capture-file, got {:?}", touchmarks));
2923	        }
2924	        let touchmark = touchmarks[0].clone();
2925	        let _ = std::fs::write(dir.join("02-touchmark.txt"), &touchmark);
2926	
2927	        // Step 2: divine enumerate shows the new Lode.
2928	        let after = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[], &[]) {
2929	            Ok(r) if r.exit_code == 0 => r,
2930	            Ok(r) => return rbtdre_Verdict::Fail(format!("post-ensconce divine failed (exit {})\n{}", r.exit_code, r.stderr)),
2931	            Err(e) => return rbtdre_Verdict::Fail(format!("post-ensconce divine invocation: {}", e)),
2932	        };
2933	        let _ = std::fs::write(dir.join("03-divine-after.txt"), &after.stdout);
2934	        if !after.stdout.contains(&touchmark) {
2935	            return rbtdre_Verdict::Fail(format!(
2936	                "post-ensconce divine missing touchmark {}\nstdout:\n{}",
2937	                touchmark, after.stdout
2938	            ));
2939	        }
2940	
2941	        // Step 3: divine inspect shows the member tags + the vouch envelope.
2942	        let inspect = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[&touchmark], &[]) {
2943	            Ok(r) if r.exit_code == 0 => r,
2944	            Ok(r) => return rbtdre_Verdict::Fail(format!("divine inspect failed (exit {})\n{}", r.exit_code, r.stderr)),
2945	            Err(e) => return rbtdre_Verdict::Fail(format!("divine inspect invocation: {}", e)),
2946	        };
2947	        let _ = std::fs::write(dir.join("04-divine-inspect.txt"), &inspect.stdout);
2948	        for member in &[RBTDRC_LODE_TAG_BOLE, RBTDRC_LODE_TAG_VOUCH, RBTDRC_LODE_TAG_DIGEST_PREFIX] {
2949	            if !inspect.stdout.contains(member) {
2950	                return rbtdre_Verdict::Fail(format!(
2951	                    "divine inspect missing member tag '{}'\nstdout:\n{}",
2952	                    member, inspect.stdout
2953	                ));
2954	            }
2955	        }
2956	
2957	        // Step 4: banish the whole Lode.
2958	        let _ = std::fs::write(dir.join("05-banish.txt"), "banishing");
2959	        match rbtdri_invoke_global(
2960	            ctx,
2961	            RBTDGC_BANISH_LODE,
2962	            &[&touchmark],
2963	            &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)],
2964	        ) {
2965	            Ok(r) if r.exit_code == 0 => {}
2966	            Ok(r) => return rbtdre_Verdict::Fail(format!("banish failed (exit {})\n{}", r.exit_code, r.stderr)),
2967	            Err(e) => return rbtdre_Verdict::Fail(format!("banish invocation: {}", e)),
2968	        }
2969	
2970	        // Step 5: divine enumerate no longer shows the Lode — registry restored.
2971	        let final_divine = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[], &[]) {
2972	            Ok(r) if r.exit_code == 0 => r,
2973	            Ok(r) => return rbtdre_Verdict::Fail(format!("final divine failed (exit {})\n{}", r.exit_code, r.stderr)),
2974	            Err(e) => return rbtdre_Verdict::Fail(format!("final divine invocation: {}", e)),
2975	        };
2976	        let _ = std::fs::write(dir.join("06-divine-final.txt"), &final_divine.stdout);
2977	        if final_divine.stdout.contains(&touchmark) {
2978	            return rbtdre_Verdict::Fail(format!(
2979	                "final divine still shows banished touchmark {} — banish did not restore baseline\nstdout:\n{}",
2980	                touchmark, final_divine.stdout
2981	            ));
2982	        }
2983	
2984	        let _ = std::fs::write(dir.join("07-passed.txt"), "passed");
2985	        rbtdre_Verdict::Pass
2986	    })
2987	}
