69	// have no context, so they read the project root from current_dir() — theurge
70	// always launches from the project root.
71	
72	fn rbtdrd_probe_root() -> Result<PathBuf, String> {
73	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
74	}
