92	/// Run `<runtime> run --rm <image_ref> <cmd>` and return Ok on exit 0. The
93	/// single site naming the container runtime — see RBTDRD_RUNTIME.
94	fn rbtdrd_runtime_run(image_ref: &str, cmd: &str, dir: &Path) -> Result<(), String> {
95	    let output = Command::new(RBTDRD_RUNTIME)
96	        .args(["run", "--rm", image_ref, cmd])
97	        .output()
98	        .map_err(|e| format!("{} run exec failed: {}", RBTDRD_RUNTIME, e))?;
99	    let _ = std::fs::write(dir.join("run-stdout.txt"), &output.stdout);
100	    let _ = std::fs::write(dir.join("run-stderr.txt"), &output.stderr);
101	    if !output.status.success() {
102	        return Err(format!(
103	            "{} run --rm {} {} exited {}: {}",
104	            RBTDRD_RUNTIME,
105	            image_ref,
106	            cmd,
107	            output.status.code().unwrap_or(-1),
108	            String::from_utf8_lossy(&output.stderr).trim()
109	        ));
110	    }
111	    Ok(())
112	}
